# Sadə funksiya dekoratoru
def my_decorator(func):
    def wrapper():
        print('Funksiya çağırılmadan əvvəl.')
        func()
        print('Funksiya çağırıldıqdan sonra.')
    return wrapper

@my_decorator
def say_hello():
    print('Salam!')

say_hello()

# Parametrlərlə dekorator
def my_decorator(func):
    def wrapper(*args, **kwargs):
        print('Funksiya çağırılmadan əvvəl.')
        result = func(*args, **kwargs)
        print('Funksiya çağırıldıqdan sonra.')
        return result
    return wrapper

@my_decorator
def greet(name):
    return f'Salam, {name}!'

print(greet('Ali'))

# Sinif dekoratoru
def class_decorator(cls):
    cls.new_attribute = 'Yeni atribut'
    return cls

@class_decorator
class MyClass:
    def __init__(self):
        self.value = 42

obj = MyClass()
print(obj.new_attribute)
print(obj.value)

# @property dekoratoru
class Person:
    def __init__(self, name):
        self._name = name

    @property
    def name(self):
        return self._name

    @name.setter
    def name(self, value):
        if value.strip():
            self._name = value
        else:
            print('Ad boş ola bilməz!')

person = Person('Veli')
print(person.name)
person.name = 'Zeynep'
print(person.name)
person.name = ''

# @staticmethod və @classmethod
class MathOperations:
    @staticmethod
    def add(a, b):
        return a + b

    @classmethod
    def multiply(cls, a, b):
        return a * b

print(MathOperations.add(3, 4))
print(MathOperations.multiply(3, 4))

