from functools import wraps
def safe_decorator(func):
    @wraps(func)
    def wrapper(*args, **kwargs):
        try:
            return func(*args, **kwargs)
        except Exception as e:
            print(f'Xəta: {e}')
            return None
    return wrapper

@safe_decorator
def divide(a, b):
    return a / b

print(divide(10, 2))
print(divide(10, 0))

# Layihədə istifadə
import time
def timer(func):
    def wrapper(*args, **kwargs):
        start = time.time()
        result = func(*args, **kwargs)
        end = time.time()
        print(f'{func.__name__} {end - start} saniyə çəkdi.')
        return result
    return wrapper

@timer
def calculate_sum(n):
    return sum(range(n))

print(calculate_sum(1000000))

